mapper.select:
SELECT c.id, c.course_name, c.description, c.coach_id, u.username AS coach_name, u.avatar AS coach_avatar, c.category, c.day_of_week, c.start_time, c.end_time, c.capacity, c.booked_count, (c.capacity - c.booked_count) AS remaining_count, c.status, c.image_url, c.difficulty_level, c.duration_minutes, c.calories_min, c.calories_max, c.total_booking_count, c.create_time FROM fitness_course c LEFT JOIN sys_user u ON c.coach_id = u.id WHERE c.deleted = false
AND c.category = #{query.category}
AND c.difficulty_level = #{query.level}
AND c.day_of_week = #{query.dayOfWeek}
AND (c.course_name LIKE '%' || #{query.keyword} || '%' OR u.username LIKE '%' || #{query.keyword} || '%')
AND c.course_name LIKE '%' || #{query.courseName} || '%'
AND c.coach_id = #{query.coachId}
AND c.duration_minutes >= #{query.minDuration}
AND c.duration_minutes <= #{query.maxDuration}
AND c.calories_max >= #{query.minCalories}
AND c.calories_min <= #{query.maxCalories}
ORDER BY c.total_booking_count DESC, c.create_time DESC
ORDER BY c.duration_minutes ASC
ORDER BY c.duration_minutes DESC
ORDER BY c.create_time DESC
